+                    var hex_buf: [6]u8 = undefined;
+                    const hex = std.fmt.bufPrint(&hex_buf, "\\u{x:0>4}", .{ch}) catch continue;
+                    try writer.writeAll(hex);
+                } else {
+                    try writer.writeByte(ch);
+                }
+            },
+        }
+    }
